-func decryptBytesWithClient(toDecrypt []byte, sdkClient *sdk.SDK) (*bytes.Buffer, error) {
-	tdfreader, err := sdkClient.LoadTDF(bytes.NewReader(toDecrypt))
-	if err != nil {
-		return nil, err
-	}
-
